import request from '@/utils/request'
import { SMS_SCENE } from '@/store'

export const user = {
  // 获取用户信息
  getUserInfo: () => {
    return request({
      url: '/api/v1/users/info/',
      method: 'get'
    })
  },

  // 修改密码
  changePassword: (data) => {
    return request({
      url: '/api/v1/users/account/password/',
      method: 'post',
      data: {
        old_password: data.old_password,
        new_password: data.new_password,
        confirm_password: data.confirm_password
      }
    })
  },

  // 更换手机号
  changePhone: (data) => {
    const token = localStorage.getItem('access_token')
    return request({
      url: '/api/v1/users/account/phone/',
      method: 'post',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': token ? `Bearer ${token}` : undefined
      },
      data: {
        new_phone: data.phone,
        code: data.code
      }
    })
  },

  // 删除账号
  deleteAccount: (data) => {
    return request({
      url: '/api/v1/users/account/delete/',
      method: 'post',
      data: {
        password: data.password
      }
    })
  }
}

// 导出需要的方法
export const { getUserInfo, changePassword, changePhone, deleteAccount } = user

// 发送短信验证码
export const sendSmsCode = (data) => {
  // 只有更换手机号场景需要 token
  const needToken = data.scene === SMS_SCENE.CHANGE_PHONE
  const token = needToken ? localStorage.getItem('access_token') : undefined

  console.log('Sending SMS code with data:', {
    phone: data.phone,
    scene: data.scene,
    needToken,
    hasToken: !!token
  })

  const config = {
    url: '/api/v1/users/auth/sms/send/',
    method: 'post',
    data: {
      phone: data.phone.trim(),
      scene: data.scene || SMS_SCENE.CHANGE_PHONE
    }
  }

  // 如果不需要 token，显式设置为 null 来覆盖默认的 token
  if (!needToken) {
    config.headers = {
      'Authorization': null
    }
  }

  return request(config).catch(error => {
    console.error('SMS code error details:', {
      status: error.response?.status,
      data: error.response?.data,
      config: error.config,
      headers: error.response?.headers
    })
    throw error
  })
}
